class Ninja:
    def __init__(self, blood, chakra):
        self.blood = blood
        self.chakra = chakra

    def katon(self):
        print('Katon! Goukakyuu no Jutsu!')
        self.chakra -= 20

    def __str__(self):
        return 'blood ' + str(self.blood) + '\n' + 'chakra ' + str(self.chakra)

class Naruto(Ninja):
    def shadow_clone(self):
        self.chakra -= 100
        print("Kage Bunshin no Jutsu!")

    def rasengan(self):
        self.chakra -= 500
        print("Rasengan!")

def main():
    naruto = Naruto(100, 2000)
    naruto.shadow_clone()
    naruto.rasengan()
    print(naruto)

main()
